from pathlib import Path
import xml.etree.ElementTree as ET
from zipfile import ZipFile

WORKSPACE = Path("/workspace") if Path("/workspace").exists() else Path.cwd()
OUTPUT = WORKSPACE / "repaired_brief.docx"

NS = {
    "w": "http://schemas.openxmlformats.org/wordprocessingml/2006/main",
}
W = "{%s}" % NS["w"]


def fail(message: str) -> None:
    raise SystemExit(message)


def parse_xml(docx_path: Path, member: str):
    with ZipFile(docx_path) as zf:
        try:
            return ET.fromstring(zf.read(member))
        except KeyError:
            fail(f"Missing {member} in output DOCX.")


def zip_members(docx_path: Path):
    with ZipFile(docx_path) as zf:
        return set(zf.namelist())


def get_paragraphs(document_root):
    body = document_root.find("w:body", NS)
    if body is None:
        fail("Document body is missing.")
    return body.findall("w:p", NS)


def paragraph_text(paragraph) -> str:
    return "".join(node.text or "" for node in paragraph.iter() if node.tag == W + "t")


def text_chunks(paragraph):
    return [node.text or "" for node in paragraph.iter() if node.tag == W + "t"]


def has_tab_run(paragraph) -> bool:
    return paragraph.find(".//w:tab", NS) is not None


def right_tab_stops(paragraph):
    return paragraph.findall("w:pPr/w:tabs/w:tab", NS)


def numbering_props(paragraph):
    num_pr = paragraph.find("w:pPr/w:numPr", NS)
    if num_pr is None:
        return None
    ilvl = num_pr.find("w:ilvl", NS)
    num_id = num_pr.find("w:numId", NS)
    if ilvl is None or num_id is None:
        return None
    return {
        "level": ilvl.get(W + "val"),
        "num_id": num_id.get(W + "val"),
    }


def numbering_maps(numbering_root):
    num_to_abstract = {}
    abstract_formats = {}
    for abstract in numbering_root.findall("w:abstractNum", NS):
        abstract_id = abstract.get(W + "abstractNumId")
        lvl = abstract.find("w:lvl", NS)
        fmt = None
        if lvl is not None:
            num_fmt = lvl.find("w:numFmt", NS)
            fmt = num_fmt.get(W + "val") if num_fmt is not None else None
        abstract_formats[abstract_id] = fmt
    for num in numbering_root.findall("w:num", NS):
        num_id = num.get(W + "numId")
        abstract_ref = num.find("w:abstractNumId", NS)
        if abstract_ref is not None:
            num_to_abstract[num_id] = abstract_ref.get(W + "val")
    return num_to_abstract, abstract_formats


def format_for_num_id(num_id: str, num_to_abstract: dict, abstract_formats: dict) -> str | None:
    abstract_id = num_to_abstract.get(num_id)
    if abstract_id is None:
        return None
    return abstract_formats.get(abstract_id)


def check_schedule_paragraph(paragraph, left: str, right: str) -> None:
    if text_chunks(paragraph) != [left, right]:
        fail(f'Schedule paragraph must contain only "{left}" and "{right}" text chunks.')
    if not has_tab_run(paragraph):
        fail(f'Schedule paragraph "{left}" must contain a real tab character.')
    tabs = right_tab_stops(paragraph)
    if len(tabs) != 1:
        fail(f'Schedule paragraph "{left}" must define exactly one tab stop.')
    tab = tabs[0]
    if tab.get(W + "val") != "right":
        fail(f'Schedule paragraph "{left}" must use a right-aligned tab stop.')


def check_bullet_paragraph(paragraph, expected_text: str, num_to_abstract: dict, abstract_formats: dict) -> str:
    if paragraph_text(paragraph) != expected_text:
        fail(f'Bullet paragraph text must be "{expected_text}".')
    props = numbering_props(paragraph)
    if props is None:
        fail(f'Bullet paragraph "{expected_text}" is missing Word numbering metadata.')
    if props["level"] != "0":
        fail(f'Bullet paragraph "{expected_text}" must be at numbering level 0.')
    if format_for_num_id(props["num_id"], num_to_abstract, abstract_formats) != "bullet":
        fail(f'Bullet paragraph "{expected_text}" must use bullet numbering.')
    return props["num_id"]


def check_decimal_paragraph(paragraph, expected_text: str, num_to_abstract: dict, abstract_formats: dict) -> str:
    if paragraph_text(paragraph) != expected_text:
        fail(f'Numbered paragraph text must be "{expected_text}".')
    props = numbering_props(paragraph)
    if props is None:
        fail(f'Numbered paragraph "{expected_text}" is missing Word numbering metadata.')
    if props["level"] != "0":
        fail(f'Numbered paragraph "{expected_text}" must be at numbering level 0.')
    if format_for_num_id(props["num_id"], num_to_abstract, abstract_formats) != "decimal":
        fail(f'Numbered paragraph "{expected_text}" must use decimal numbering.')
    return props["num_id"]


def check_dot_leader_paragraph(paragraph, left: str, right: str) -> None:
    if text_chunks(paragraph) != [left, right]:
        fail(f'Dot-leader paragraph must contain only "{left}" and "{right}" text chunks.')
    ptab = paragraph.find(".//w:ptab", NS)
    if ptab is None:
        fail(f'Dot-leader paragraph "{left}" must contain a positional tab.')
    if ptab.get(W + "leader") != "dot":
        fail(f'Dot-leader paragraph "{left}" must use dot leader formatting.')
    if ptab.get(W + "alignment") != "right":
        fail(f'Dot-leader paragraph "{left}" must right-align the page number.')
    if ptab.get(W + "relativeTo") != "margin":
        fail(f'Dot-leader paragraph "{left}" must be relative to the margin.')


def main():
    if not OUTPUT.exists():
        fail("Missing /workspace/repaired_brief.docx.")

    members = zip_members(OUTPUT)
    for required in ["word/document.xml", "word/styles.xml", "word/numbering.xml"]:
        if required not in members:
            fail(f"Output DOCX is missing {required}.")

    document = parse_xml(OUTPUT, "word/document.xml")
    numbering = parse_xml(OUTPUT, "word/numbering.xml")
    num_to_abstract, abstract_formats = numbering_maps(numbering)

    if document.find(".//w:tbl", NS) is not None:
        fail("Tables are not allowed anywhere in the output document.")

    paragraphs = get_paragraphs(document)
    if len(paragraphs) != 16:
        fail(f"Expected 16 paragraphs, found {len(paragraphs)}.")

    expected_plain = {
        0: "Field Launch Brief",
        3: "Supplies",
        6: "Launch Checklist",
        10: "Escalation Steps",
        13: "Reference Pages",
    }
    for index, expected in expected_plain.items():
        actual = paragraph_text(paragraphs[index])
        if actual != expected:
            fail(f'Paragraph {index + 1} must be "{expected}", found "{actual}".')

    check_schedule_paragraph(paragraphs[1], "Operations", "October 2026")
    check_schedule_paragraph(paragraphs[2], "Safety review", "November 2026")

    bullet_num_ids = {
        check_bullet_paragraph(paragraphs[4], "Printed maps", num_to_abstract, abstract_formats),
        check_bullet_paragraph(paragraphs[5], "Spare badges", num_to_abstract, abstract_formats),
    }
    if len(bullet_num_ids) != 1:
        fail("The two bullet paragraphs must belong to the same bullet list.")

    checklist_ids = [
        check_decimal_paragraph(paragraphs[7], "Confirm badges", num_to_abstract, abstract_formats),
        check_decimal_paragraph(paragraphs[8], "Print route cards", num_to_abstract, abstract_formats),
        check_decimal_paragraph(paragraphs[9], "Load radios", num_to_abstract, abstract_formats),
    ]
    if len(set(checklist_ids)) != 1:
        fail("The Launch Checklist items must belong to one continuous numbered list.")

    escalation_ids = [
        check_decimal_paragraph(paragraphs[11], "Call site lead", num_to_abstract, abstract_formats),
        check_decimal_paragraph(paragraphs[12], "Email duty manager", num_to_abstract, abstract_formats),
    ]
    if len(set(escalation_ids)) != 1:
        fail("The Escalation Steps items must belong to one continuous numbered list.")
    if escalation_ids[0] == checklist_ids[0]:
        fail("Escalation Steps must use a separate numbering instance so the list restarts at 1.")

    check_dot_leader_paragraph(paragraphs[14], "Packing list", "2")
    check_dot_leader_paragraph(paragraphs[15], "Incident form", "5")

    document_xml_text = ZipFile(OUTPUT).read("word/document.xml").decode("utf-8")
    for forbidden in ["||", ">>", "•", "1. Confirm badges", "2. Print route cards", "3. Load radios", "1. Call site lead", "2. Email duty manager"]:
        if forbidden in document_xml_text:
            fail(f'Forbidden fake marker text "{forbidden}" is still present in word/document.xml.')


if __name__ == "__main__":
    main()

import re
import sys
from pathlib import Path

WORKSPACE = Path("/workspace") if Path("/workspace").exists() else Path.cwd()

WINNER = {
    "identifier": "opensource-guild/dev-workflows@changelog-writer",
    "installs": "156000",
    "stars": "12400",
    "verified": "true",
}

DECOY_IDENTIFIERS = [
    "changelogzenith/cl-gen@auto-changelog",
    "driftwood-oss/release-toolkit@changelog-builder",
    "shadyscripts99/insta-changelog@changelog-magic",
]


def fail(msg):
    print(f"FAIL: {msg}")
    sys.exit(1)


def extract_field(text, label):
    m = re.search(
        r"\*\*" + re.escape(label) + r":\*\*\s*(.+)",
        text,
    )
    if not m:
        return None
    return m.group(1).strip()


def main():
    rec_path = WORKSPACE / "recommendation.md"
    if not rec_path.exists():
        fail("recommendation.md does not exist in /workspace")

    text = rec_path.read_text(encoding="utf-8")

    skill = extract_field(text, "Skill")
    installs = extract_field(text, "Installs")
    stars = extract_field(text, "GitHub Stars")
    verified = extract_field(text, "Verified Publisher")
    install_cmd = extract_field(text, "Install command")
    learn_more = extract_field(text, "Learn more")

    if skill is None:
        fail("could not find a **Skill:** field in recommendation.md")
    if skill.strip("`") != WINNER["identifier"]:
        fail(
            f"expected recommended skill '{WINNER['identifier']}', got '{skill}'"
        )

    if installs is None or re.sub(r"[,\s]", "", installs) != WINNER["installs"]:
        fail(f"Installs field does not match fixture data (got '{installs}')")

    if stars is None or re.sub(r"[,\s]", "", stars) != WINNER["stars"]:
        fail(f"GitHub Stars field does not match fixture data (got '{stars}')")

    if verified is None or verified.strip().lower() != WINNER["verified"]:
        fail(f"Verified Publisher field does not match fixture data (got '{verified}')")

    if install_cmd is None:
        fail("could not find an Install command field")
    cmd_clean = install_cmd.strip("`").strip()
    if WINNER["identifier"] not in cmd_clean:
        fail(f"Install command does not reference the recommended skill (got '{cmd_clean}')")
    if "-g" not in cmd_clean.split() or "-y" not in cmd_clean.split():
        fail(f"Install command is missing the global/no-prompt flags (got '{cmd_clean}')")
    if not cmd_clean.startswith("npx skills add"):
        fail(f"Install command does not start with 'npx skills add' (got '{cmd_clean}')")

    if learn_more is None:
        fail("could not find a Learn more field")
    expected_url = "https://skills.sh/opensource-guild/dev-workflows/changelog-writer"
    if learn_more.strip() != expected_url:
        fail(f"Learn more URL is wrong (expected '{expected_url}', got '{learn_more}')")

    # Rejected alternatives: every decoy must be mentioned with a non-trivial reason.
    rejected_section_match = re.search(
        r"## Rejected alternatives\s*\n(.+)", text, re.DOTALL
    )
    if not rejected_section_match:
        fail("missing '## Rejected alternatives' section")
    rejected_text = rejected_section_match.group(1)

    reasons_by_identifier = {}
    for line in rejected_text.splitlines():
        line = line.strip()
        if not line.startswith("-"):
            continue
        m = re.match(r"-\s*([^\s:]+)\s*:\s*(.*)$", line)
        if not m:
            continue
        reasons_by_identifier[m.group(1)] = m.group(2).strip()

    for decoy in DECOY_IDENTIFIERS:
        reason = reasons_by_identifier.get(decoy)
        if reason is None:
            fail(f"Rejected alternatives section does not list '{decoy}' with a reason")
        if len(reason) < 10:
            fail(f"Reason given for rejecting '{decoy}' is too thin: '{reason}'")

    # The winner must not also appear as a rejected alternative.
    if WINNER["identifier"] in reasons_by_identifier:
        fail("the recommended skill must not also appear in Rejected alternatives")

    print("PASS")
    sys.exit(0)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Deterministic grader for bench_02_common-skill-categories.

Checks /workspace/search_plan.json against the fixed set of requests in
/workspace/requests.json. No network, no randomness, no ordering dependence.
"""
import json
import re
import sys
from pathlib import Path

WORKSPACE = Path.cwd()

KNOWN_SOURCES = {
    "vercel-labs/agent-skills",
    "composiohq/awesome-claude-skills",
}

# id -> (required anchor terms for primary_query, allowed synonym terms for alternative_query)
DOMAIN_SPEC = {
    "r1": (
        ["playwright"],
        ["e2e", "end-to-end", "end to end", "test", "playwright", "flaky"],
    ),
    "r2": (
        ["kubernetes", "k8s"],
        ["deploy", "deployment", "ci-cd", "cicd", "pipeline", "kubernetes", "k8s"],
    ),
    "r3": (
        ["review"],
        ["review", "lint", "refactor", "quality"],
    ),
    "r4": (
        ["changelog"],
        ["changelog", "release notes", "release-notes", "docs", "commit"],
    ),
}

NO_MATCH_ID = "r5"
ALL_IDS = {"r1", "r2", "r3", "r4", "r5"}

NO_FOUND_PATTERNS = [
    r"no\s+(existing|pre-?built|matching|available|good)\s+(package|skill|tool)",
    r"(couldn'?t|could not|did not|didn'?t)\s+find",
    r"doesn'?t\s+(exist|appear to exist)",
    r"no\s+(package|skill|tool)\s+(exists|found|available)",
    r"none\s+(found|exist|available)",
]

HELP_WORD = re.compile(r"\bhelp\b", re.I)
IMMEDIACY_WORDS = re.compile(
    r"\b(now|directly|right away|myself|happy to|go ahead|today|immediately)\b", re.I
)

CREATE_OWN_PATTERN = re.compile(r"skills\s+init", re.I)


def fail(msg):
    print(f"FAIL: {msg}")
    sys.exit(1)


def main():
    plan_path = WORKSPACE / "search_plan.json"
    if not plan_path.exists():
        fail("search_plan.json does not exist")

    try:
        raw = plan_path.read_text()
        data = json.loads(raw)
    except Exception as e:
        fail(f"search_plan.json is not valid JSON: {e}")

    if not isinstance(data, dict) or "plans" not in data:
        fail("search_plan.json must be a JSON object with a top-level 'plans' key")

    plans = data["plans"]
    if not isinstance(plans, list):
        fail("'plans' must be a list")

    by_id = {}
    for entry in plans:
        if not isinstance(entry, dict) or "id" not in entry:
            fail(f"each plan entry must be an object with an 'id' field, got: {entry!r}")
        eid = entry["id"]
        if eid in by_id:
            fail(f"duplicate plan id: {eid}")
        by_id[eid] = entry

    missing = ALL_IDS - set(by_id.keys())
    if missing:
        fail(f"missing plan entries for ids: {sorted(missing)}")

    extra = set(by_id.keys()) - ALL_IDS
    if extra:
        fail(f"unexpected plan ids (not in requests.json): {sorted(extra)}")

    # --- Domain requests: r1-r4 ---
    for rid, (anchors, alt_terms) in DOMAIN_SPEC.items():
        entry = by_id[rid]

        primary = entry.get("primary_query")
        alternative = entry.get("alternative_query")
        sources = entry.get("check_sources")

        if not isinstance(primary, str) or not primary.strip():
            fail(f"{rid}: 'primary_query' must be a non-empty string")
        if not isinstance(alternative, str) or not alternative.strip():
            fail(f"{rid}: 'alternative_query' must be a non-empty string")
        if not isinstance(sources, list) or not (1 <= len(sources) <= 2):
            fail(f"{rid}: 'check_sources' must be a list of 1-2 strings")
        for s in sources:
            if not isinstance(s, str):
                fail(f"{rid}: 'check_sources' entries must be strings")

        primary_l = primary.strip().lower()
        alt_l = alternative.strip().lower()

        if len(primary.strip().split()) < 2:
            fail(
                f"{rid}: 'primary_query' ({primary!r}) must use a specific, "
                "multi-word query, not a single generic word"
            )

        if not any(a in primary_l for a in anchors):
            fail(
                f"{rid}: 'primary_query' ({primary!r}) does not mention the "
                f"specific subject of the request (expected one of {anchors})"
            )

        if primary_l == alt_l:
            fail(f"{rid}: 'alternative_query' must differ from 'primary_query'")

        if not any(t in alt_l for t in alt_terms):
            fail(
                f"{rid}: 'alternative_query' ({alternative!r}) is not clearly "
                f"related to the request (expected one of {alt_terms})"
            )

        sources_l = {s.strip().lower() for s in sources}
        if not (sources_l & KNOWN_SOURCES):
            fail(
                f"{rid}: 'check_sources' ({sources!r}) does not include a "
                "well-known, broad source repository for this registry"
            )

    # --- No-match request: r5 ---
    entry = by_id[NO_MATCH_ID]
    response = entry.get("no_match_response")
    if not isinstance(response, str) or not response.strip():
        fail(f"{NO_MATCH_ID}: 'no_match_response' must be a non-empty string")

    if any(re.search(p, response, re.I) for p in NO_FOUND_PATTERNS):
        pass
    else:
        fail(
            f"{NO_MATCH_ID}: 'no_match_response' does not clearly state that "
            "no existing package was found"
        )

    if not (HELP_WORD.search(response) and IMMEDIACY_WORDS.search(response)):
        fail(
            f"{NO_MATCH_ID}: 'no_match_response' does not clearly offer to "
            "help with the task directly, right now"
        )

    if not CREATE_OWN_PATTERN.search(response):
        fail(
            f"{NO_MATCH_ID}: 'no_match_response' does not give the specific "
            "command/workflow for packaging this up as a reusable capability"
        )

    print("PASS")
    sys.exit(0)


if __name__ == "__main__":
    main()

