#!/usr/bin/env python3
"""Deterministic + LLM-judge grader for the brainstorm/critique/build benchmark."""
import json
import os
import re
import sys
from pathlib import Path

WORKSPACE = Path(os.environ.get("BENCH_WORKSPACE", "/workspace"))
JUDGE_DIR = WORKSPACE / ".judge"

AXES = ["Color", "Type", "Layout", "Signature"]
REQUIRED_FILES = [
    "design/initial-plan.md",
    "design/critique.md",
    "design/final-plan.md",
    "index.html",
    "styles.css",
]


def fail(msg):
    print(f"FAIL: {msg}")
    sys.exit(1)


def read(path):
    p = WORKSPACE / path
    if not p.exists():
        fail(f"missing required file: {path}")
    return p.read_text(encoding="utf-8", errors="replace")


def section(text, heading):
    """Return the body text of a '## Heading' section, up to the next '## '."""
    m = re.search(
        rf"^##\s*{re.escape(heading)}\s*$(.*?)(?=^##\s|\Z)",
        text,
        re.MULTILINE | re.DOTALL,
    )
    if not m:
        return None
    return m.group(1).strip("\n")


def parse_colors(body, label):
    if body is None:
        fail(f"{label}: missing '## Color' section")
    lines = [l for l in body.splitlines() if l.strip().startswith("-")]
    colors = []
    for line in lines:
        m = re.search(r"#([0-9A-Fa-f]{6})", line)
        if not m:
            continue
        hexval = m.group(1).lower()
        name_part = line[: m.start()]
        name = re.sub(r"^-\s*", "", name_part)
        name = re.sub(r"[—\-:]\s*$", "", name).strip()
        colors.append((name, hexval))
    if not (4 <= len(colors) <= 6):
        fail(
            f"{label}: Color section must have 4-6 named hex colors, found {len(colors)}"
        )
    return colors


def parse_types(body, label):
    if body is None:
        fail(f"{label}: missing '## Type' section")
    lines = [l for l in body.splitlines() if l.strip().startswith("-")]
    roles = {}
    for line in lines:
        m = re.match(r"^-\s*(Display|Body|Utility)\s*:\s*(.+)$", line.strip())
        if not m:
            continue
        role, rest = m.group(1), m.group(2)
        font = re.split(r"—|(?:\s-\s)", rest, maxsplit=1)[0].strip()
        roles[role] = font
    if "Display" not in roles or "Body" not in roles:
        fail(f"{label}: Type section must include at least Display and Body roles")
    if not (2 <= len(roles) <= 3):
        fail(f"{label}: Type section must have 2-3 roles, found {len(roles)}")
    return roles


def parse_layout(body, label):
    if body is None:
        fail(f"{label}: missing '## Layout' section")
    fence = re.search(r"```(.*?)```", body, re.DOTALL)
    if not fence:
        fail(f"{label}: Layout section must contain a fenced ASCII wireframe")
    wireframe = fence.group(1).strip("\n")
    wf_lines = [l for l in wireframe.splitlines() if l.strip()]
    if len(wf_lines) < 4:
        fail(f"{label}: Layout wireframe must have at least 4 non-empty lines")
    chars_used = set(c for l in wf_lines for c in l if c in "+-|/\\_")
    if len(chars_used) < 2:
        fail(f"{label}: Layout wireframe doesn't look like a structural sketch")
    prose = body[: fence.start()].strip()
    if len(prose) < 15:
        fail(f"{label}: Layout section is missing prose description")
    normalized = "\n".join(l.strip() for l in wf_lines)
    return {"prose": prose, "wireframe": normalized}


def parse_signature(body, label):
    if body is None:
        fail(f"{label}: missing '## Signature' section")
    m = re.search(r"^Slug:\s*([a-z0-9-]+)\s*$", body, re.MULTILINE)
    if not m:
        fail(f"{label}: Signature section must have a 'Slug: <kebab-slug>' line")
    slug = m.group(1)
    desc = body[m.end():].strip()
    if len(desc) < 15:
        fail(f"{label}: Signature section is missing a description")
    return {"slug": slug, "desc": desc}


def parse_plan(text, label):
    return {
        "colors": parse_colors(section(text, "Color"), label),
        "types": parse_types(section(text, "Type"), label),
        "layout": parse_layout(section(text, "Layout"), label),
        "signature": parse_signature(section(text, "Signature"), label),
    }


def parse_critique(text):
    verdicts = {}
    for axis in AXES:
        m = re.search(
            rf"^-\s*{axis}\s*:\s*(KEEP|REVISE)\s*[—\-]\s*(.+)$", text, re.MULTILINE
        )
        if not m:
            fail(
                f"critique.md: missing a '- {axis}: KEEP|REVISE — <reason>' line"
            )
        verdict, reason = m.group(1), m.group(2).strip()
        if len(reason) < 20:
            fail(f"critique.md: {axis} reason is too short to be a real justification")
        verdicts[axis] = {"verdict": verdict, "reason": reason}
    if not any(v["verdict"] == "REVISE" for v in verdicts.values()):
        fail("critique.md: at least one axis must be marked REVISE")
    return verdicts


def color_set(colors):
    return set(hexval for _, hexval in colors)


def type_tuple(types):
    return tuple(sorted((role, font.lower()) for role, font in types.items()))


def check_axis_consistency(verdicts, initial, final):
    c = verdicts["Color"]["verdict"]
    same_colors = color_set(initial["colors"]) == color_set(final["colors"])
    if c == "KEEP" and not same_colors:
        fail("final-plan.md: Color marked KEEP but palette differs from initial-plan.md")
    if c == "REVISE" and same_colors:
        fail("final-plan.md: Color marked REVISE but palette is identical to initial-plan.md")

    t = verdicts["Type"]["verdict"]
    same_types = type_tuple(initial["types"]) == type_tuple(final["types"])
    if t == "KEEP" and not same_types:
        fail("final-plan.md: Type marked KEEP but fonts differ from initial-plan.md")
    if t == "REVISE" and same_types:
        fail("final-plan.md: Type marked REVISE but fonts are identical to initial-plan.md")

    lay = verdicts["Layout"]["verdict"]
    same_layout = initial["layout"]["wireframe"] == final["layout"]["wireframe"]
    if lay == "KEEP" and not same_layout:
        fail("final-plan.md: Layout marked KEEP but wireframe differs from initial-plan.md")
    if lay == "REVISE" and same_layout:
        fail("final-plan.md: Layout marked REVISE but wireframe is identical to initial-plan.md")

    sig = verdicts["Signature"]["verdict"]
    same_slug = initial["signature"]["slug"] == final["signature"]["slug"]
    if sig == "KEEP" and not same_slug:
        fail("final-plan.md: Signature marked KEEP but slug differs from initial-plan.md")
    if sig == "REVISE" and same_slug:
        fail("final-plan.md: Signature marked REVISE but slug is identical to initial-plan.md")


def check_build(final):
    try:
        from bs4 import BeautifulSoup
    except ImportError:
        fail("bs4 not available in grading environment")

    html = read("index.html")
    css = read("styles.css")
    soup = BeautifulSoup(html, "lxml")

    if not soup.find("html") or not soup.find("head") or not soup.find("body"):
        fail("index.html: must be a full document with html/head/body")

    viewport = soup.find("meta", attrs={"name": "viewport"})
    if not viewport:
        fail("index.html: missing a viewport meta tag")

    link = soup.find("link", attrs={"rel": "stylesheet"})
    if not link or "styles.css" not in (link.get("href") or ""):
        fail("index.html: must link styles.css as a stylesheet")

    if not soup.find(["h1", "h2"]):
        fail("index.html: missing a heading")

    slug = final["signature"]["slug"]
    sig_el = soup.find(attrs={"data-signature": slug})
    if not sig_el:
        fail(f"index.html: no element has data-signature=\"{slug}\" matching final-plan.md")

    visible_text = soup.get_text(" ", strip=True)
    lower_text = visible_text.lower()
    for fact in ["aria", "9 bar", "walnut"]:
        if fact not in lower_text:
            fail(f"index.html: page copy must mention '{fact}' from the brief")

    for banned in ["lorem ipsum", "placeholder text"]:
        if banned in lower_text:
            fail(f"index.html: contains placeholder text ('{banned}')")
    if re.search(r"\btodo\b", lower_text):
        fail("index.html: contains a TODO placeholder")

    has_mailto = bool(soup.find("a", href=re.compile(r"^mailto:")))
    has_form = bool(soup.find("form"))
    if not (has_mailto or has_form):
        fail("index.html: no waitlist form or mailto link found")

    final_hexes = color_set(final["colors"])
    css_hexes = set(h.lower() for h in re.findall(r"#([0-9A-Fa-f]{6})\b", css))
    overlap = final_hexes & css_hexes
    needed = -(-len(final_hexes) // 2)  # ceil(n/2)
    if len(overlap) < needed:
        fail(
            "styles.css: must use most of final-plan.md's palette hex codes "
            f"(found {len(overlap)}/{len(final_hexes)})"
        )

    css_lower = css.lower()
    for role in ("Display", "Body"):
        font = final["types"][role].lower()
        if font not in css_lower:
            fail(f"styles.css: does not reference the {role} font '{final['types'][role]}'")

    if "@media" not in css:
        fail("styles.css: missing a responsive @media breakpoint")

    if not re.search(r":focus(-visible)?", css):
        fail("styles.css: missing a visible :focus rule")

    return visible_text


def main():
    for f in REQUIRED_FILES:
        if not (WORKSPACE / f).exists():
            fail(f"missing required file: {f}")

    initial_text = read("design/initial-plan.md")
    critique_text = read("design/critique.md")
    final_text = read("design/final-plan.md")

    initial = parse_plan(initial_text, "initial-plan.md")
    verdicts = parse_critique(critique_text)
    final = parse_plan(final_text, "final-plan.md")

    check_axis_consistency(verdicts, initial, final)
    visible_text = check_build(final)

    answers_path = JUDGE_DIR / "answers.json"
    if answers_path.exists():
        answers = json.loads(answers_path.read_text()).get("answers", {})
        if not answers.get("q1") or not answers.get("q2"):
            fail("judge determined the critique reasoning or page copy is not substantive")
        print("PASS")
        sys.exit(0)

    revise_reasons = " | ".join(
        f"{axis}: {v['reason']}" for axis, v in verdicts.items() if v["verdict"] == "REVISE"
    )
    product_context = (
        "Product context: a fully manual, spring-lever espresso machine (no pump, "
        "no PID controller) with brushed brass fittings, a matte black steel body, "
        "a walnut lever handle, and 9 bar of pressure produced by hand."
    )

    questions = {
        "questions": [
            {
                "id": "q1",
                "question": (
                    f"{product_context} A designer revised part of their initial plan "
                    "and gave the following reasons. For EVERY reason listed, does it "
                    "identify a specific, non-generic replacement that is clearly "
                    "motivated by this particular product (its mechanism, materials, "
                    "or audience), rather than an arbitrary, cosmetic, or unrelated "
                    f"tweak? Reasons: {revise_reasons}"
                ),
            },
            {
                "id": "q2",
                "question": (
                    f"{product_context} Does the following webpage copy read as "
                    "specific to this particular product (using its concrete "
                    "mechanism, materials, price, or process) rather than generic, "
                    "interchangeable marketing filler that could describe almost any "
                    f"premium gadget? Copy: {visible_text}"
                ),
            },
        ]
    }
    JUDGE_DIR.mkdir(parents=True, exist_ok=True)
    (JUDGE_DIR / "questions.json").write_text(json.dumps(questions, indent=2))
    sys.exit(3)


if __name__ == "__main__":
    main()

#!/usr/bin/env python3
"""Grader for bench_04_restraint-and-self-critique.

The fixture (draft.html) is a deliberately over-decorated homepage: five
competing attention-grabbing effects, a fixed-width desktop-only layout, a
blanket `outline: none`, and infinite CSS animations with no
prefers-reduced-motion handling. The task asks the agent to cut it down to one
signature moment, fix the quality-floor bugs, and document the changes.

This grader checks (deterministically):
  1. index.html and CHANGES.md exist.
  2. The real facts from the draft survive into index.html's visible text.
  3. Exactly one element carries data-signature="true", and it has an id.
  4. At most one of the draft's five decorative features is still present.
  5. The specific fixed-width bug is gone and a mobile breakpoint exists.
  6. The blanket outline-removal bug is gone and a real focus-visible
     indicator exists.
  7. Any remaining looping animation is neutralized under
     prefers-reduced-motion: reduce.
  8. CHANGES.md substantively names what was removed/kept and what
     accessibility fixes were made.
Then it asks an LLM judge two qualitative questions about restraint and about
the specificity of CHANGES.md.
"""
import json
import os
import re
import sys
from pathlib import Path

WORKSPACE = Path(os.environ.get("BENCH_WORKSPACE", "/workspace"))
JUDGE_DIR = WORKSPACE / ".judge"
QUESTIONS_PATH = JUDGE_DIR / "questions.json"
ANSWERS_PATH = JUDGE_DIR / "answers.json"

DRAFT_PATH = WORKSPACE / "draft.html"
HTML_PATH = WORKSPACE / "index.html"
CHANGES_PATH = WORKSPACE / "CHANGES.md"

DECOR_CLASSES = [
    "bounce-logo",
    "glow-pulse-cta",
    "ticker-marquee",
    "confetti-burst",
    "rainbow-bg",
]

BANNED_FILLER = [
    "lorem ipsum",
    "tbd",
    "n/a",
    "placeholder text",
    "your text here",
    "insert text here",
]

REMOVED_EFFECT_KEYWORDS = {
    "bounce": ["bounce", "bouncing"],
    "glow": ["glow", "pulse", "pulsing", "pulsed"],
    "ticker": ["ticker", "marquee", "scroll"],
    "confetti": ["confetti"],
    "rainbow": ["rainbow"],
}

QUALITY_FLOOR_KEYWORDS = {
    "mobile": ["mobile", "phone", "responsive", "viewport"],
    "focus": ["focus", "keyboard"],
    "motion": ["motion", "reduced motion", "reduce motion", "animation"],
}


def fail(msg: str):
    print(f"FAIL: {msg}")
    sys.exit(1)


def load_files():
    if not DRAFT_PATH.exists():
        fail("draft.html is missing from /workspace (the input fixture was removed)")
    if not HTML_PATH.exists():
        fail("index.html is missing from /workspace")
    if not CHANGES_PATH.exists():
        fail("CHANGES.md is missing from /workspace")
    html_text = HTML_PATH.read_text(encoding="utf-8")
    changes_text = CHANGES_PATH.read_text(encoding="utf-8")
    return html_text, changes_text


def parse_html(html_text: str):
    from bs4 import BeautifulSoup

    soup = BeautifulSoup(html_text, "lxml")
    if soup.find("html") is None:
        fail("index.html has no <html> element")
    if soup.find("head") is None:
        fail("index.html has no <head> element")
    if soup.find("body") is None:
        fail("index.html has no <body> element")
    return soup


def get_css_text(soup) -> str:
    style_tags = soup.find_all("style")
    css_text = "\n".join(tag.get_text() for tag in style_tags)
    if not css_text.strip():
        fail("index.html has no inline <style> content to read CSS from")
    return css_text


def check_facts_preserved(soup):
    body_text = soup.get_text(" ", strip=True)
    lower = body_text.lower()
    if "warble press" not in lower:
        fail("index.html no longer mentions the company name 'Warble Press'")
    if "2016" not in body_text:
        fail("index.html no longer states the founding year (2016)")
    if not re.search(r"\b500\b", body_text):
        fail("index.html no longer states the daily press capacity (500)")
    if not re.search(r"6[\s-]*week", lower):
        fail("index.html no longer states the turnaround time (6-week / 6 week)")
    if not re.search(r"\b100\b", body_text):
        fail("index.html no longer states the minimum order size (100)")


def check_viewport(soup):
    viewport = soup.find("meta", attrs={"name": "viewport"})
    if viewport is None or "width=device-width" not in (viewport.get("content") or ""):
        fail("index.html is missing a <meta name='viewport' content='width=device-width...'> tag")


def check_signature(soup):
    matches = soup.find_all(attrs={"data-signature": "true"})
    if len(matches) == 0:
        fail("no element in index.html has data-signature=\"true\"")
    if len(matches) > 1:
        fail(f"more than one element has data-signature=\"true\" ({len(matches)} found); exactly one is required")
    sig = matches[0]
    sig_id = sig.get("id")
    if not sig_id or not sig_id.strip():
        fail("the data-signature=\"true\" element must also have a non-empty id attribute")
    return sig, sig_id.strip()


def check_decor_removed(soup):
    remaining = []
    for cls in DECOR_CLASSES:
        if soup.find(class_=cls) is not None:
            remaining.append(cls)
    if len(remaining) > 1:
        fail(
            "too many of the draft's original decorative effects are still present "
            f"({remaining}); at most one of the five may remain"
        )
    return remaining


def check_no_fixed_width_bug(css_text: str):
    if re.search(r"width\s*:\s*1200px", css_text, re.IGNORECASE):
        fail("index.html's CSS still hardcodes the draft's fixed width:1200px layout bug")
    breakpoints = re.findall(r"@media[^{]*max-width\s*:\s*(\d+)px", css_text, re.IGNORECASE)
    if not any(int(bp) <= 768 for bp in breakpoints):
        fail("index.html's CSS has no @media rule with a mobile breakpoint (max-width <= 600px)")


def check_focus(css_text: str):
    if re.search(r"\*\s*:\s*focus\s*\{[^}]*outline\s*:\s*(none|0)\b", css_text, re.IGNORECASE):
        fail("index.html's CSS still contains the draft's blanket '*:focus { outline: none }' rule")

    rule_re = re.compile(r"([^{}]+)\{([^{}]*)\}")
    has_visible_focus = False
    for selector_group, body in rule_re.findall(css_text):
        if ":focus" not in selector_group.lower():
            continue
        outline_m = re.search(r"outline(?:-\w+)?\s*:\s*([^;]+)", body, re.IGNORECASE)
        shadow_m = re.search(r"box-shadow\s*:\s*([^;]+)", body, re.IGNORECASE)
        border_m = re.search(r"border(?:-\w+)?\s*:\s*([^;]+)", body, re.IGNORECASE)
        for m in (outline_m, shadow_m, border_m):
            if m is None:
                continue
            value = m.group(1).strip().lower()
            if value not in ("none", "0", "0px") :
                has_visible_focus = True
    if not has_visible_focus:
        fail(
            "index.html's CSS has no ':focus' / ':focus-visible' rule that sets a visible "
            "outline, box-shadow, or border (a real replacement for the removed default outline)"
        )


def extract_media_block(css_text: str, marker: str):
    """Return the body of the first @media block whose prelude contains `marker`, or None."""
    idx = css_text.lower().find("@media")
    while idx != -1:
        brace_idx = css_text.find("{", idx)
        if brace_idx == -1:
            break
        prelude = css_text[idx:brace_idx]
        if marker.lower() in prelude.lower():
            depth = 1
            pos = brace_idx + 1
            start = pos
            while pos < len(css_text) and depth > 0:
                if css_text[pos] == "{":
                    depth += 1
                elif css_text[pos] == "}":
                    depth -= 1
                pos += 1
            return css_text[start:pos - 1]
        idx = css_text.lower().find("@media", brace_idx)
    return None


def check_reduced_motion(css_text: str):
    keyframes = re.findall(r"@keyframes\s+([\w-]+)", css_text, re.IGNORECASE)
    animated = bool(re.search(r"animation(?:-name)?\s*:\s*(?!none\b)[\w-]", css_text, re.IGNORECASE))
    if not keyframes and not animated:
        return  # nothing looping left; reduced-motion handling isn't required

    block = extract_media_block(css_text, "prefers-reduced-motion")
    if block is None:
        fail(
            "index.html keeps a looping CSS animation but has no "
            "@media (prefers-reduced-motion: reduce) block to neutralize it"
        )
    if not re.search(r"(animation|transition)", block, re.IGNORECASE):
        fail(
            "the prefers-reduced-motion media query in index.html doesn't actually "
            "reference animation/transition to turn the motion off"
        )


def check_changes_md(changes_text: str, sig_id: str):
    lower = changes_text.lower()
    for phrase in BANNED_FILLER:
        if phrase in lower:
            fail(f"CHANGES.md contains banned filler text: {phrase!r}")

    word_count = len(changes_text.split())
    if word_count < 60:
        fail(f"CHANGES.md is too short ({word_count} words) to substantively explain the revision")

    if sig_id.lower() not in lower:
        fail(f"CHANGES.md never mentions the signature element's id ({sig_id!r})")

    matched_effects = [name for name, kws in REMOVED_EFFECT_KEYWORDS.items() if any(kw in lower for kw in kws)]
    if len(matched_effects) < 3:
        fail(
            "CHANGES.md doesn't name at least 3 of the draft's original effects "
            f"(bounce/glow/ticker/confetti/rainbow) it removed or kept; found: {matched_effects}"
        )

    matched_floor = [name for name, kws in QUALITY_FLOOR_KEYWORDS.items() if any(kw in lower for kw in kws)]
    if len(matched_floor) < 2:
        fail(
            "CHANGES.md doesn't describe at least 2 of the mobile/focus/motion fixes it made; "
            f"found: {matched_floor}"
        )


def run_deterministic_checks():
    html_text, changes_text = load_files()
    soup = parse_html(html_text)
    check_facts_preserved(soup)
    check_viewport(soup)
    sig, sig_id = check_signature(soup)
    check_decor_removed(soup)
    css_text = get_css_text(soup)
    check_no_fixed_width_bug(css_text)
    check_focus(css_text)
    check_reduced_motion(css_text)
    check_changes_md(changes_text, sig_id)
    print("Deterministic checks passed.")
    return html_text, changes_text, sig_id


def ask_judge(html_text: str, changes_text: str):
    JUDGE_DIR.mkdir(exist_ok=True)

    page_source = html_text
    if len(page_source) > 8000:
        page_source = page_source[:8000]

    changes_source = changes_text
    if len(changes_source) > 4000:
        changes_source = changes_source[:4000]

    questions = [
        {
            "id": "one_signature_rest_calm",
            "question": (
                "Below is the full HTML and inline CSS source of a homepage. "
                "Reading it as a whole page (imagine how it would render), does it "
                "read as having exactly ONE clear bold or attention-grabbing visual "
                "moment, with everything else on the page (colors, type, other "
                "elements) staying calm, quiet, and disciplined rather than "
                "competing for attention? Answer yes only if there is a single "
                "standout moment and the rest is genuinely restrained, not if "
                "there are still multiple flashy or heavily animated elements, "
                "and not if the page has been made so plain that there is no "
                "standout moment at all."
            ),
            "text": page_source,
        },
        {
            "id": "changes_specific",
            "question": (
                "Below is a changelog written by a designer explaining a revision "
                "to a homepage draft for Warble Press, an independent vinyl record "
                "pressing plant. Does the changelog give specific, concrete "
                "reasoning tied to this particular draft and this particular "
                "business (e.g. referring to actual effects that were removed, or "
                "explaining why the specific element that was kept fits this "
                "business), rather than generic boilerplate that could describe "
                "cutting down almost any website ('we simplified the design and "
                "improved accessibility')?"
            ),
            "text": changes_source,
        },
    ]
    QUESTIONS_PATH.write_text(json.dumps({"questions": questions}, indent=2), encoding="utf-8")
    print("Wrote judge questions; awaiting answers.")
    sys.exit(3)


def evaluate_judge_answers():
    answers = json.loads(ANSWERS_PATH.read_text(encoding="utf-8")).get("answers", {})
    required_ids = ["one_signature_rest_calm", "changes_specific"]
    for qid in required_ids:
        if qid not in answers:
            fail(f"missing judge answer for {qid!r}")
        if answers[qid] is not True:
            fail(f"judge answered 'no' (or non-true) for {qid!r}")
    print("Judge checks passed.")
    sys.exit(0)


def main():
    html_text, changes_text, _sig_id = run_deterministic_checks()
    if ANSWERS_PATH.exists():
        evaluate_judge_answers()
    else:
        ask_judge(html_text, changes_text)


if __name__ == "__main__":
    main()

import json
import os
import re
import sys

WORKDIR = os.environ.get("BENCH_WORKDIR", "/workspace")
COPY_PATH = os.path.join(WORKDIR, "ui_copy.json")

REQUIRED_KEYS = {
    "archive_action": ["button_label", "confirmation_message"],
    "remove_member_action": ["button_label", "confirmation_message"],
    "upload_error": ["message"],
    "empty_folder_state": ["heading", "body"],
}

# Internal/implementation terms from system_notes.md / limits.json that should never
# leak into text a customer sees. Short/ambiguous tokens are matched on word
# boundaries so legitimate words (e.g. "megabytes") aren't falsely flagged.
BANNED_WORD_BOUNDARY = [
    "endpoint", "webhook", "cron", "backend", "schema", "payload", "config",
    "database", "query", "byte", "bytes", "api", "json", "null", "boolean",
    "row", "server",
]
BANNED_SUBSTRING = [
    "sync_group", "sync-group", "syncgroup", "soft-delete", "soft delete",
    "revoke_membership", "max_upload_bytes", "314572800",
]

BANNED_APOLOGY = [
    "sorry", "apolog", "oops", "unfortunately", "something went wrong",
    "an error occurred", "error occurred",
]

GENERIC_BUTTON_LABELS = {"submit", "ok", "okay", "click here", "yes", "confirm"}

ACTIONABLE_FIX_WORDS = ["smaller", "compress", "reduce", "split", "shrink"]


def fail(msg):
    print("FAIL: " + msg)
    sys.exit(1)


def load_copy():
    if not os.path.isfile(COPY_PATH):
        fail("ui_copy.json not found in /workspace")
    try:
        with open(COPY_PATH) as f:
            return json.load(f)
    except Exception as e:
        fail(f"ui_copy.json is not valid JSON: {e}")


def all_strings(data):
    out = []

    def walk(x):
        if isinstance(x, str):
            out.append(x)
        elif isinstance(x, dict):
            for v in x.values():
                walk(v)
        elif isinstance(x, list):
            for v in x:
                walk(v)

    walk(data)
    return out


def verb_stem(word):
    w = re.sub(r"[^a-z]", "", word.lower())
    if len(w) > 4 and w.endswith("e"):
        return w[:-1]
    return w


def check_structure(data):
    errors = []
    if not isinstance(data, dict):
        return ["ui_copy.json must contain a JSON object"]
    for key, subkeys in REQUIRED_KEYS.items():
        if key not in data or not isinstance(data[key], dict):
            errors.append(f"missing or malformed key: {key}")
            continue
        for sk in subkeys:
            val = data[key].get(sk)
            if not isinstance(val, str) or not val.strip():
                errors.append(f"missing or empty field: {key}.{sk}")
    return errors


def check_content(data):
    errors = []
    strs = all_strings(data)
    joined = "\n".join(strs).lower()

    for term in BANNED_WORD_BOUNDARY:
        if re.search(r"\b" + re.escape(term) + r"\b", joined):
            errors.append(f"internal/system jargon leaked into user-facing copy: '{term}'")

    for term in BANNED_SUBSTRING:
        if term in joined:
            errors.append(f"internal/system jargon leaked into user-facing copy: '{term}'")

    for term in BANNED_APOLOGY:
        if term in joined:
            errors.append(f"apologetic/vague filler language found: '{term}'")

    for key in ["archive_action", "remove_member_action"]:
        label = data[key]["button_label"].strip().lower().rstrip("!.")
        if label in GENERIC_BUTTON_LABELS:
            errors.append(f"{key}.button_label is a generic, non-descriptive label: '{label}'")

        words = re.findall(r"[a-z]+", label)
        first_word = words[0] if words else ""
        stem = verb_stem(first_word)
        confirmation = data[key]["confirmation_message"].lower()
        if not stem or stem not in confirmation:
            errors.append(
                f"{key}: confirmation_message doesn't clearly refer back to the same "
                f"action named in button_label ('{first_word}')"
            )

    upload_msg = data["upload_error"]["message"].lower()
    if "300" not in upload_msg or ("mb" not in upload_msg and "megabyte" not in upload_msg):
        errors.append(
            "upload_error.message doesn't state the actual size limit in "
            "human-readable form (300 MB)"
        )
    if not any(w in upload_msg for w in ACTIONABLE_FIX_WORDS):
        errors.append(
            "upload_error.message doesn't tell the person a concrete way to fix the problem"
        )

    empty_text = (
        data["empty_folder_state"]["heading"] + " " + data["empty_folder_state"]["body"]
    ).lower()
    if "upload" not in empty_text:
        errors.append("empty_folder_state doesn't invite the person to upload a file")

    return errors


def build_questions(data):
    return {
        "questions": [
            {
                "id": "q1",
                "question": (
                    "In the JSON below, do BOTH action pairs (archive_action and "
                    "remove_member_action) show a button_label and a confirmation_message "
                    "that clearly describe the same user action, so the confirmation reads "
                    "as the natural result of pressing that specific button rather than a "
                    "generic or mismatched confirmation? Answer yes only if this holds for "
                    "both pairs."
                ),
                "text": json.dumps(
                    {k: data[k] for k in ["archive_action", "remove_member_action"]}, indent=2
                ),
            },
            {
                "id": "q2",
                "question": (
                    "Does this error message clearly state what specifically went wrong "
                    "and clearly tell the person a concrete way to fix it, in a neutral "
                    "tone with no apology and no vague phrasing?"
                ),
                "text": data["upload_error"]["message"],
            },
            {
                "id": "q3",
                "question": (
                    "Does this empty-state text read as an invitation for the person to "
                    "take a specific action to fill the empty space, rather than merely "
                    "stating that nothing is there yet?"
                ),
                "text": data["empty_folder_state"]["heading"]
                + " — "
                + data["empty_folder_state"]["body"],
            },
            {
                "id": "q4",
                "question": (
                    "Below are the on-screen text strings a customer would actually see "
                    "in the product (field names/labels are not shown, only the text "
                    "itself). Is all of it written in plain, conversational language that "
                    "a non-technical small-business customer would understand, with no "
                    "internal engineering or system terminology (such as database "
                    "tables, APIs, config values, or internal code names) anywhere in it?"
                ),
                "text": "\n".join(all_strings(data)),
            },
        ]
    }


def main():
    data = load_copy()

    errors = check_structure(data)
    if errors:
        for e in errors:
            print("FAIL: " + e)
        sys.exit(1)

    errors = check_content(data)
    if errors:
        for e in errors:
            print("FAIL: " + e)
        sys.exit(1)

    judge_dir = os.path.join(WORKDIR, ".judge")
    answers_path = os.path.join(judge_dir, "answers.json")
    questions_path = os.path.join(judge_dir, "questions.json")

    if os.path.isfile(answers_path):
        with open(answers_path) as f:
            answers = json.load(f).get("answers", {})
        required_ids = ["q1", "q2", "q3", "q4"]
        missing_or_no = [qid for qid in required_ids if not answers.get(qid)]
        if missing_or_no:
            print(f"FAIL: judge answered no (or didn't answer) for: {missing_or_no}")
            sys.exit(1)
        print("PASS")
        sys.exit(0)
    else:
        os.makedirs(judge_dir, exist_ok=True)
        with open(questions_path, "w") as f:
            json.dump(build_questions(data), f, indent=2)
        sys.exit(3)


if __name__ == "__main__":
    main()

