DATA_PATH = os.path.join(WORKSPACE, "sales_data.json")
GRADING_DIR = os.path.join(WORKSPACE, ".grading")
JUDGE_DIR = os.path.join(WORKSPACE, ".judge")
QUESTIONS_PATH = os.path.join(JUDGE_DIR, "questions.json")
