            ["pdftotext", "-layout", PDF_PATH, "-"],
            capture_output=True, text=True, timeout=30,
        )
    except Exception as e:
        fail(f"pdftotext failed to run: {e}")

    if proc.returncode != 0:
        fail(f"pdftotext exited with error: {proc.stderr}")

    text = proc.stdout

